header("Access-Control-Allow-Origin: *");
header("Access-Control-Allow-Methods: POST, OPTIONS");
header("Access-Control-Allow-Headers: Content-Type, Authorization");
function uploadBase64ImageToImmich(
    string $base64Input,
    string $apiKey,
    string $baseUrl = 'http://127.0.0.1:2283/api',
    string $deviceId = 'php-base64-upload'
): array {
    $mimeType = 'image/jpeg';
    $base64 = $base64Input;


    if (preg_match('#^data:(.+?);base64,(.*)$#', $base64Input, $matches)) {
        $mimeType = $matches[1];
        $base64 = $matches[2];
    }


    $binary = base64_decode($base64, true);
    if ($binary === false) {
        throw new InvalidArgumentException('Invalid base64 image data');
    }


    $ext = match ($mimeType) {
        'image/jpeg', 'image/jpg' => 'jpg',
        'image/png' => 'png',
        'image/webp' => 'webp',
        'image/heic' => 'heic',
        default => 'bin',
    };


    $tmpPath = tempnam(sys_get_temp_dir(), 'immich_');
    if ($tmpPath === false) {
        throw new RuntimeException('Failed to create temp file');
    }


    $finalPath = $tmpPath . '.' . $ext;
    rename($tmpPath, $finalPath);


    if (file_put_contents($finalPath, $binary) === false) {
        @unlink($finalPath);
        throw new RuntimeException('Failed to write temp image file');
    }


    $mtime = time();
    $isoTime = date(DATE_ATOM, $mtime);
    $filename = 'upload-' . date('Ymd-His') . '.' . $ext;


    $postFields = [
        'assetData'      => new CURLFile($finalPath, $mimeType, $filename),
        'deviceAssetId'  => $filename . '-' . $mtime,
        'deviceId'       => $deviceId,
        'fileCreatedAt'  => $isoTime,
        'fileModifiedAt' => $isoTime,
        'filename'       => $filename,
        'isFavorite'     => 'false',
    ];


    $ch = curl_init($baseUrl . '/assets');
    curl_setopt_array($ch, [
        CURLOPT_POST => true,
        CURLOPT_RETURNTRANSFER => true,
        CURLOPT_HTTPHEADER => [
            'Accept: application/json',
            'x-api-key: ' . $apiKey,
        ],
        CURLOPT_POSTFIELDS => $postFields,
    ]);


    $response = curl_exec($ch);


    if ($response === false) {
        $error = curl_error($ch);
        curl_close($ch);
        @unlink($finalPath);
        throw new RuntimeException('cURL error: ' . $error);
    }


    $statusCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);
    @unlink($finalPath);


    return [
        'status' => $statusCode,
        'body' => json_decode($response, true),
        'raw' => $response,
    ];
}


